// DEBUG: Voir exactement ce que retourne Google Drive
const items = $input.all();

// Log brut
const rawData = items.map(i => i.json);

// Compter les types
let dossiers = 0;
let fichiers = 0;
let autres = 0;
const nomsElements = [];

for (const item of items) {
  const data = item.json;
  if (!data || !data.id) {
    autres++;
    continue;
  }

  nomsElements.push({
    nom: data.name || '(sans nom)',
    type: data.mimeType === 'application/vnd.google-apps.folder' ? 'DOSSIER' : 'fichier',
    id: data.id
  });

  if (data.mimeType === 'application/vnd.google-apps.folder') {
    dossiers++;
  } else {
    fichiers++;
  }
}

return [{
  json: {
    debug: true,
    timestamp: new Date().toISOString(),
    statistiques: {
      totalItems: items.length,
      dossiers: dossiers,
      fichiers: fichiers,
      itemsVides: autres
    },
    premierItem: items.length > 0 ? items[0].json : null,
    tousLesElements: nomsElements.slice(0, 50),
    message: items.length === 0 
      ? 'PROBLEME: Aucun élément retourné par Google Drive. Vérifiez le credential OAuth2.'
      : `OK: ${items.length} éléments trouvés (${dossiers} dossiers, ${fichiers} fichiers)`
  }
}];
